import asyncio
import websockets
import json

class Item:
    def __init__(self, name, owner):
        self.name = name
        self.owner = owner

class Player:
    def __init__(self, id):
        self.id = id
        self.inventory = []

    def add_item(self, item):
        self.inventory.append(item)

    def remove_item(self, item_name):
        for item in self.inventory:
            if item.name == item_name:
                self.inventory.remove(item)
                return True
        return False

class GameServer:
    def __init__(self):
        self.players = {}
        self.locks = {}

    async def register_player(self, player_id):
        if player_id not in self.players:
            self.players[player_id] = Player(player_id)
            self.locks[player_id] = asyncio.Lock()

    async def handle_message(self, websocket, path):
        async for message in websocket:
            data = json.loads(message)
            action = data.get('action')
            if action == 'register':
                await self.register_player(data['player_id'])
            elif action == 'add_item':
                player_id = data['player_id']
                item_name = data['item_name']
                async with self.locks[player_id]:
                    self.players[player_id].add_item(Item(item_name, player_id))
            elif action == 'remove_item':
                player_id = data['player_id']
                item_name = data['item_name']
                async with self.locks[player_id]:
                    if self.players[player_id].remove_item(item_name):
                        print(f"Item {item_name} removed from {player_id}'s inventory.")
            elif action == 'trade_items':
                sender_id = data['sender_id']
                receiver_id = data['receiver_id']
                item_name = data['item_name']
                async with self.locks[sender_id], self.locks[receiver_id]:
                    if self.players[sender_id].remove_item(item_name):
                        self.players[receiver_id].add_item(Item(item_name, receiver_id))
                        print(f"Item {item_name} traded from {sender_id} to {receiver_id}.")
            else:
                await websocket.send(json.dumps({'status': 'error', 'message': 'Invalid action'}))

start_server = websockets.serve(GameServer().handle_message, "localhost", 6789)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()